package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

class JsonTreeReaderTest {

  private JsonTreeReader reader;

  @BeforeEach
  void setUp() throws Exception {
    // Create a JsonElement to initialize JsonTreeReader
    JsonObject jsonObject = new JsonObject();
    jsonObject.add("key", new JsonPrimitive("value"));
    reader = new JsonTreeReader(jsonObject);
  }

  @Test
  void nextJsonElement_shouldReturnElementAndSkipValue_whenPeekIsValid() throws Exception {
    // Use reflection to get private methods peekStack() and skipValue()
    Method peekStackMethod = JsonTreeReader.class.getDeclaredMethod("peekStack");
    peekStackMethod.setAccessible(true);
    Method skipValueMethod = JsonTreeReader.class.getDeclaredMethod("skipValue");
    skipValueMethod.setAccessible(true);

    // Spy on the reader to stub peek() and verify skipValue() call
    JsonTreeReader spyReader = spy(reader);

    // Stub peek() to return a valid JsonToken (e.g. BEGIN_OBJECT)
    doReturn(JsonToken.BEGIN_OBJECT).when(spyReader).peek();

    // Stub peekStack() to return a JsonElement (e.g. JsonObject) using reflection
    JsonObject element = new JsonObject();
    doReturn(element).when(spyReader).peek();

    // Instead of stubbing peekStack() directly (private), stub peekStack via reflection
    // We cannot stub private methods directly with Mockito, so we override peekStack via reflection:
    // We'll create a proxy method that replaces peekStack() temporarily for the spy
    // But since this is complex, we can stub peekStack by using Mockito's doAnswer with reflection:

    // Remove previous doReturn for peek() to avoid conflict
    reset(spyReader);
    doReturn(JsonToken.BEGIN_OBJECT).when(spyReader).peek();

    // Create a spy that overrides peekStack() via reflection
    // Use doAnswer to intercept peekStack calls
    doAnswer(invocation -> element).when(spyReader).peekStack();

    // To allow this, we need to make peekStack accessible in spyReader's class
    // But Mockito cannot stub private methods directly, so instead we use reflection to replace peekStack call

    // Since Mockito can't stub private methods, we will use reflection to replace peekStack method call temporarily
    // So we create a subclass that overrides peekStack to return element

    JsonTreeReader spyWithOverride = new JsonTreeReader(reader.peek()) {
      @Override
      protected Object peekStack() {
        return element;
      }
      @Override
      public JsonToken peek() {
        return JsonToken.BEGIN_OBJECT;
      }
      @Override
      public void skipValue() {
        super.skipValue();
      }
    };

    JsonTreeReader spyReaderFinal = spy(spyWithOverride);

    // Call nextJsonElement() via reflection since it has package-private access
    Method nextJsonElementMethod = JsonTreeReader.class.getDeclaredMethod("nextJsonElement");
    nextJsonElementMethod.setAccessible(true);
    JsonElement result = (JsonElement) nextJsonElementMethod.invoke(spyReaderFinal);

    // Verify returned element is the one from peekStack()
    assertSame(element, result);

    // Verify skipValue() was called once
    verify(spyReaderFinal, times(1)).skipValue();
  }

  @Test
  void nextJsonElement_shouldThrowIllegalStateException_whenPeekIsName() throws Exception {
    JsonTreeReader spyReader = spy(reader);
    doReturn(JsonToken.NAME).when(spyReader).peek();

    Method nextJsonElementMethod = JsonTreeReader.class.getDeclaredMethod("nextJsonElement");
    nextJsonElementMethod.setAccessible(true);

    Exception exception = assertThrows(Exception.class, () -> {
      nextJsonElementMethod.invoke(spyReader);
    });
    Throwable cause = exception.getCause();
    assertTrue(cause instanceof IllegalStateException);
    assertTrue(cause.getMessage().contains("Unexpected NAME"));
  }

  @Test
  void nextJsonElement_shouldThrowIllegalStateException_whenPeekIsEndArray() throws Exception {
    JsonTreeReader spyReader = spy(reader);
    doReturn(JsonToken.END_ARRAY).when(spyReader).peek();

    Method nextJsonElementMethod = JsonTreeReader.class.getDeclaredMethod("nextJsonElement");
    nextJsonElementMethod.setAccessible(true);

    Exception exception = assertThrows(Exception.class, () -> {
      nextJsonElementMethod.invoke(spyReader);
    });
    Throwable cause = exception.getCause();
    assertTrue(cause instanceof IllegalStateException);
    assertTrue(cause.getMessage().contains("Unexpected END_ARRAY"));
  }

  @Test
  void nextJsonElement_shouldThrowIllegalStateException_whenPeekIsEndObject() throws Exception {
    JsonTreeReader spyReader = spy(reader);
    doReturn(JsonToken.END_OBJECT).when(spyReader).peek();

    Method nextJsonElementMethod = JsonTreeReader.class.getDeclaredMethod("nextJsonElement");
    nextJsonElementMethod.setAccessible(true);

    Exception exception = assertThrows(Exception.class, () -> {
      nextJsonElementMethod.invoke(spyReader);
    });
    Throwable cause = exception.getCause();
    assertTrue(cause instanceof IllegalStateException);
    assertTrue(cause.getMessage().contains("Unexpected END_OBJECT"));
  }

  @Test
  void nextJsonElement_shouldThrowIllegalStateException_whenPeekIsEndDocument() throws Exception {
    JsonTreeReader spyReader = spy(reader);
    doReturn(JsonToken.END_DOCUMENT).when(spyReader).peek();

    Method nextJsonElementMethod = JsonTreeReader.class.getDeclaredMethod("nextJsonElement");
    nextJsonElementMethod.setAccessible(true);

    Exception exception = assertThrows(Exception.class, () -> {
      nextJsonElementMethod.invoke(spyReader);
    });
    Throwable cause = exception.getCause();
    assertTrue(cause instanceof IllegalStateException);
    assertTrue(cause.getMessage().contains("Unexpected END_DOCUMENT"));
  }
}
